CREATE OR REPLACE FUNCTION fpa_fin_desc_by_dep (as_acc_id char,as_vch_no char,ai_seqno integer,as_type char) RETURNS varchar AS $body$
DECLARE

  ls_account_tr sc_fin_vourcher_detail.account_tr%type;
  ls_return varchar(100);

BEGIN
