  end;
 if as_acc_id = ls_account_tr then
   if trim(both as_type) = 'DESC' then
      select	account_name into STRICT ls_return
      from		sc_acc_m_account_master
      where (account_id = ls_account_tr);
   elsif trim(both as_type) = 'MONEY_TYPE' then
     -- select  fin_book into
    --  from    sc_fin_vourcher_head
    --  where   ()
      null;
   else
      null;
   end if;
 else
   null;
 end if;

 return ls_return;
exception when others then CALL spa_dberror('FPA_FIN_DESC_BY_DEP');return null;
END;
